class Solution:
    def projectionArea(self, grid):
        rows = len(grid)
        cols = len(grid[0]) if grid else 0
        top = 0
        front = 0
        col_max = [0] * cols
        for r in range(rows):
            row_max = 0
            for c in range(cols):
                v = grid[r][c]
                if v > 0:
                    top += 1
                if v > row_max:
                    row_max = v
                if v > col_max[c]:
                    col_max[c] = v
            front += row_max
        side = sum(col_max)
        return top + front + side

